arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0 and life>0
  {
    if initDir=0
    {
      if x>oPlayer1.x {image_xscale=-1}
      initDir=1
    }
    
    spikeDrop+=1
    if startUp=0
    {
      if spikeDrop=8 {image_index=1}
      else if spikeDrop=16 {xVel=runAcc*image_xscale; image_index=2; spikeDrop=-1; startUp=1}
    }
    else if startUp=1
    {
      if xVel>0
        image_xscale=1
      else
        image_xscale=-1
      
      if spikeDrop mod 32=0
      {
        if spikeAmt<12
        {
          var newSpike;
          newSpike=instance_create(x-(8*image_xscale),y-16,oStaticSpike)
          spikeAmt+=1
        }
      }
      
      if spikeDrop mod 11=0
      {
        if image_index=2 {image_index=3}
        else {image_index=2}
      }
    }
    
    yVel+=0.2
    if isCollisionBottom(1)
      yVel=0
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+24
    {
      if questType>0
        enemyQuest(questType)
      instance_destroy()
    }
  }
  else if life<=0
  {
    playSound(global.snd_EnemyDieMM,0,1,1)
    tEffect=instance_create(x,y-18,oEffect)
    tEffect.sprite_index=sMMExplosion
    tEffect.newBlend=-1; tEffect.followID=-1; tEffect.decay=-100; tEffect.xSpd=0; tEffect.ySpd=0
    instance_destroy()
  }
  enemyStepEvent()
}
